# Module defining the shape hierarchy with abstract base classes and interfaces

@abstract
class Shape:
    """Abstract base class for all shapes"""
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def area(self) -> float: ...

    @abstract
    def perimeter(self) -> float: ...

    @virtual
    def describe(self) -> str:
        return f"Shape: {self.name}"


class Rectangle(Shape):
    """Rectangle implementation"""
    width: float
    height: float

    def __init__(self, name: str, width: float, height: float):
        super().__init__(name)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)


class Circle(Shape):
    """Circle implementation"""
    radius: float

    def __init__(self, name: str, radius: float):
        super().__init__(name)
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def describe(self) -> str:
        return f"Circle({self.name}) with radius {self.radius}"


interface IResizable:
    """Interface for resizable shapes"""
    def resize(self, factor: float) -> None


interface IColorable:
    """Interface for colorable objects"""
    def set_color(self, color: str) -> None
    def get_color(self) -> str


class ColoredRectangle(Rectangle, IColorable):
    """Rectangle that can have a color"""
    color: str

    def __init__(self, name: str, width: float, height: float, color: str):
        super().__init__(name, width, height)
        self.color = color

    @override
    def set_color(self, color: str) -> None:
        self.color = color

    @override
    def get_color(self) -> str:
        return self.color

