# Module for geometric utilities using structs and value types

struct Point:
    """2D point struct with value semantics"""
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_to(self, other: Point) -> float:
        dx: float = self.x - other.x
        dy: float = self.y - other.y
        return pow(dx * dx + dy * dy, 0.5)


struct Size:
    """Size dimensions struct"""
    width: float
    height: float

    def __init__(self, width: float, height: float):
        self.width = width
        self.height = height

    def area(self) -> float:
        return self.width * self.height


enum ShapeType:
    """Enum for shape classification"""
    RECTANGLE = 1
    CIRCLE = 2
    TRIANGLE = 3
    POLYGON = 4


def calculate_bounding_box(points: list[Point]) -> Size:
    """Calculate bounding box size from points"""
    if len(points) == 0:
        return Size(0.0, 0.0)

    min_x: float = points[0].x
    max_x: float = points[0].x
    min_y: float = points[0].y
    max_y: float = points[0].y

    for p in points:
        if p.x < min_x:
            min_x = p.x
        if p.x > max_x:
            max_x = p.x
        if p.y < min_y:
            min_y = p.y
        if p.y > max_y:
            max_y = p.y

    return Size(max_x - min_x, max_y - min_y)

