# Utility module with helper functions and constants

const PI_APPROX: float = 3.14159
const DEFAULT_COLOR: str = "gray"


def format_number(n: float, decimals: int) -> str:
    """Format a number with specified decimal places"""
    factor: float = pow(10.0, float(decimals))
    rounded: float = round(n * factor) / factor
    return f"{rounded}"


def sum_areas(shapes: list[Shape]) -> float:
    """Calculate total area of all shapes"""
    total: float = 0.0
    for s in shapes:
        total = total + s.area()
    return total


def classify_shape(shape: Shape) -> str:
    """Classify a shape by its type"""
    if isinstance(shape, Circle):
        return "circular"
    elif isinstance(shape, Rectangle):
        return "rectangular"
    else:
        return "unknown"


def create_point_grid(rows: int, cols: int, spacing: float) -> list[Point]:
    """Create a grid of points"""
    points: list[Point] = []
    for r in range(rows):
        for c in range(cols):
            x: float = float(c) * spacing
            y: float = float(r) * spacing
            points.append(Point(x, y))
    return points


class ShapeStats:
    """Statistics collector for shapes"""
    count: int
    total_area: float

    def __init__(self):
        self.count = 0
        self.total_area = 0.0

    def add_shape(self, shape: Shape) -> None:
        self.count = self.count + 1
        self.total_area = self.total_area + shape.area()

    def get_average(self) -> float:
        if self.count == 0:
            return 0.0
        return self.total_area / float(self.count)
